import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [recognizedText, setRecognizedText] = useState("");

  // 기기 카메라를 실행하여 사진을 촬영하고 Base64 데이터를 가져옴
  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 100,
        allowEditing: true,
        resultType: CameraResultType.Base64,
        source: CameraSource.Camera,
      });
      setPhoto(image.base64String);
      setRecognizedText("");
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  // 촬영된 사진 데이터를 백엔드 서버로 전송하여 텍스트 결과 수신
  const startOCR = async () => {
    if (!photo) return;
    setUploading(true);

    try {
      const response = await fetch("http://192.168.200.116:3001/ocr", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ image: photo }),
      });

      if (!response.ok) throw new Error("서버 응답 에러");

      const data = await response.json();
      setRecognizedText(data.text);
    } catch (err) {
      console.error("통신 오류:", err);
      alert("서버와 연결할 수 없습니다.");
    } finally {
      setUploading(false);
    }
  };

  const deletePhoto = () => {
    setPhoto(null);
    setRecognizedText("");
  };

  return (
    <div style={wrapperStyle}>
      <header style={headerStyle}>
        <h1 style={headerTitleStyle}>
          <span style={{ marginRight: "8px" }}>🔍</span>
          글자 읽어주기
        </h1>
      </header>

      <main style={mainStyle}>
        <div style={photoCardStyle}>
          {photo ? (
            <div style={imageWrapperStyle}>
              <img
                src={`data:image/jpeg;base64,${photo}`}
                alt="Preview"
                style={imageStyle}
              />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </div>
          ) : (
            <div style={placeholderStyle}>
              <div style={iconCircleStyle}>📄</div>
              <p style={placeholderTextStyle}>스캔할 대상을 촬영해 주세요</p>
              <span style={hintTextStyle}>글자가 밝은 곳에서 잘 보여요</span>
            </div>
          )}
        </div>

        <div style={infoSectionStyle}>
          {uploading ? (
            <div style={loadingAreaStyle}>
              <div className="spinner" style={spinnerStyle}></div>
              <p style={statusStyle}>글자를 읽고 있습니다...</p>
            </div>
          ) : recognizedText ? (
            <div style={resultContainerStyle}>
              <div style={resultHeaderStyle}>
                <span style={labelStyle}>인식 결과</span>
                <button
                  onClick={() => navigator.clipboard.writeText(recognizedText)}
                  style={copyButtonStyle}
                >
                  복사하기
                </button>
              </div>
              <textarea style={textareaStyle} value={recognizedText} readOnly />
            </div>
          ) : (
            photo && (
              <p style={readyTextStyle}>준비 완료! 아래 버튼을 눌러주세요.</p>
            )
          )}
        </div>
      </main>

      <footer style={footerStyle}>
        {!photo ? (
          <button onClick={takePhoto} style={primaryButtonStyle}>
            사진 촬영하기
          </button>
        ) : (
          <button
            onClick={startOCR}
            style={actionButtonStyle}
            disabled={uploading}
          >
            {uploading ? "읽는 중..." : "글자 읽어오기"}
          </button>
        )}
      </footer>

      <style>{`
        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
        .spinner { animation: spin 1s linear infinite; }
        button:active { transform: scale(0.98); }
      `}</style>
    </div>
  );
}

const wrapperStyle = {
  background: "linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)",
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily: "-apple-system, sans-serif",
  color: "#2d3436",
};
const headerStyle = {
  paddingTop: "60px",
  paddingBottom: "20px",
  backgroundColor: "rgba(255, 255, 255, 0.8)",
  backdropFilter: "blur(10px)",
  textAlign: "center",
  borderBottom: "1px solid rgba(0,0,0,0.05)",
  position: "sticky",
  top: 0,
  zIndex: 100,
};
const headerTitleStyle = {
  fontSize: "22px",
  margin: 0,
  fontWeight: "800",
  color: "#6c5ce7",
};
const mainStyle = {
  flex: 1,
  padding: "24px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const photoCardStyle = {
  width: "100%",
  maxWidth: "400px",
  aspectRatio: "4/5",
  backgroundColor: "rgba(255, 255, 255, 0.6)",
  borderRadius: "32px",
  border: "1px solid rgba(255, 255, 255, 0.8)",
  boxShadow: "0 20px 40px rgba(0,0,0,0.08)",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  overflow: "hidden",
  position: "relative",
};
const imageWrapperStyle = {
  width: "100%",
  height: "100%",
  position: "relative",
};
const imageStyle = { width: "100%", height: "100%", objectFit: "cover" };
const placeholderStyle = { textAlign: "center", padding: "40px" };
const iconCircleStyle = {
  fontSize: "48px",
  backgroundColor: "#fff",
  width: "90px",
  height: "90px",
  borderRadius: "50%",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  margin: "0 auto 20px",
  boxShadow: "0 10px 20px rgba(0,0,0,0.05)",
};
const placeholderTextStyle = {
  fontSize: "18px",
  fontWeight: "700",
  color: "#4b4b4b",
  marginBottom: "8px",
};
const hintTextStyle = { fontSize: "14px", color: "#95a5a6" };
const closeButtonStyle = {
  position: "absolute",
  top: "20px",
  right: "20px",
  width: "36px",
  height: "36px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.3)",
  color: "#fff",
  border: "none",
  fontSize: "18px",
};
const infoSectionStyle = {
  width: "100%",
  maxWidth: "400px",
  marginTop: "30px",
};
const readyTextStyle = {
  textAlign: "center",
  color: "#6c5ce7",
  fontWeight: "600",
  fontSize: "15px",
};
const resultContainerStyle = {
  backgroundColor: "#fff",
  borderRadius: "20px",
  padding: "16px",
  boxShadow: "0 10px 25px rgba(0,0,0,0.05)",
};
const resultHeaderStyle = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  marginBottom: "12px",
};
const labelStyle = { fontSize: "13px", fontWeight: "800", color: "#6c5ce7" };
const copyButtonStyle = {
  background: "none",
  border: "none",
  color: "#0984e3",
  fontSize: "12px",
  fontWeight: "600",
};
const textareaStyle = {
  width: "100%",
  minHeight: "150px",
  border: "none",
  fontSize: "15px",
  lineHeight: "1.6",
  color: "#2d3436",
  outline: "none",
  resize: "none",
};
const loadingAreaStyle = {
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const spinnerStyle = {
  width: "40px",
  height: "40px",
  border: "4px solid rgba(108, 92, 231, 0.1)",
  borderTop: "4px solid #6c5ce7",
  borderRadius: "50%",
};
const statusStyle = {
  fontSize: "15px",
  marginTop: "15px",
  color: "#636e72",
  fontWeight: "500",
};
const footerStyle = { padding: "30px 24px" };
const primaryButtonStyle = {
  width: "100%",
  padding: "20px",
  borderRadius: "24px",
  border: "none",
  backgroundColor: "#6c5ce7",
  color: "#fff",
  fontSize: "18px",
  fontWeight: "700",
  boxShadow: "0 10px 20px rgba(108, 92, 231, 0.3)",
};
const actionButtonStyle = {
  ...primaryButtonStyle,
  backgroundColor: "#00b894",
  boxShadow: "0 10px 20px rgba(0, 184, 148, 0.3)",
};

export default App;
